    REFERENCES "courses"("courseId")
    ON DELETE RESTRICT
    ON UPDATE RESTRICT
    NOT DEFERRABLE;

ALTER TABLE "questions" ADD CONSTRAINT "Ref_questions_to_vfsFiles" FOREIGN KEY ("photoFileId")
    REFERENCES "vfsFiles"("fileId")
    ON DELETE SET NULL
    ON UPDATE RESTRICT
    NOT DEFERRABLE;

