    REFERENCES "statuses"("statusId")
    ON DELETE RESTRICT
    ON UPDATE RESTRICT
    NOT DEFERRABLE;

ALTER TABLE "exams" ADD CONSTRAINT "Ref_exams_to_courses" FOREIGN KEY ("courseId")
    REFERENCES "courses"("courseId")
    ON DELETE RESTRICT
    ON UPDATE RESTRICT
    NOT DEFERRABLE;

ALTER TABLE "exams" ADD CONSTRAINT "Ref_exams_to_students" FOREIGN KEY ("studentId")
    REFERENCES "students"("studentId")
    ON DELETE RESTRICT
    ON UPDATE RESTRICT
    NOT DEFERRABLE;

